var e=[{id:`L3_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`예하!!`,JPN:`猊下！！`,ENG:`Your Eminence!!`,TWN:`主教！！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`정신 차리세요……!! 예하!!`,JPN:`しっかりしてください……！！　猊下！！`,ENG:`Wake up...! Your Eminence!!`,TWN:`你醒醒……！！主教！！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CARDINAL_VATICAN_SUPPLEMENT_NPC`,text:{KOREA:`이…… 목소리는…… 비블리데?`,JPN:`この……声は……ビブリデ？`,ENG:`That voice... Is that you... Biblide?`,TWN:`這……聲音是……布莉黛？`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`예하, 아무 말씀도 하시지 마세요!`,JPN:`猊下、言葉を発してはなりません！`,ENG:`Your Eminence, please do not talk!`,TWN:`主教，你不要說話！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`지금 지혈해 드리겠습니다! 조금만 참으세요!`,JPN:`今止血します！　もう少し我慢してください！`,ENG:`I will try to stop the bleeding! Stay with me!`,TWN:`我立刻替你止血！你忍耐一下！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SERIOUS`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CARDINAL_VATICAN_SUPPLEMENT_NPC`,text:{KOREA:`비블리데, 나의 딸아…….`,JPN:`ビブリデ、我が娘よ……`,ENG:`Oh Biblide... My daughter...`,TWN:`布莉黛，我的女兒……`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CARDINAL_VATICAN_SUPPLEMENT_NPC`,text:{KOREA:`그동안…… 내가 너무 너를…….`,JPN:`これまで……私は君に……`,ENG:`I apologize for... not paying enough attention...`,TWN:`過去……我對你太……`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`말씀하지 마세요!`,JPN:`お話しになってはいけません！`,ENG:`Please, stop talking!`,TWN:`別說了！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CARDINAL_VATICAN_SUPPLEMENT_NPC`,text:{KOREA:`부디…… 그 어리석은 녀석을……`,JPN:`どうか……あの愚かな子を……`,ENG:`Please... save that foolish...`,TWN:`求你……救救那傻小子……`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`제게…… 제게 또 그런 부탁하지 마세요, 제발……!`,JPN:`私に……私にまたそんなことを頼まないでください、お願い……！`,ENG:`Please...! Do not ask that of me...!`,TWN:`不要……我做不到，拜託……！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_DESPAIR`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`CARDINAL_VATICAN_SUPPLEMENT_NPC`,text:{KOREA:`그, 그 맹신은…… 구원은커녕…… 파멸만이…….`,JPN:`そ、その盲信は……救いはおろか……破滅だけが……`,ENG:`H-his blind faith... only destruction... not salvation...`,TWN:`盲從……只會帶來毀滅……不會帶來救贖……`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CARDINAL_VATICAN_SUPPLEMENT_NPC`,text:{KOREA:`지금이라도…… 주의 품으로……!`,JPN:`今でも……主の元へ……！`,ENG:`It is not too late... the Lord's arms...!`,TWN:`快將他……帶回天主的……！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`제발, 제발……! 아직 한 번도 아버지라고 불러드린 적 없는데……!`,JPN:`お願い、お願いします……！　まだ一度も父とお呼びできていません……！`,ENG:`Please...! I still have not had the chance to call you father even once...!`,TWN:`拜託，你不要死……！我都還沒叫過你一聲爸爸……！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`죄송해요, 죄송해요…… 그러니까……!!`,JPN:`ごめんなさい、ごめんなさい……だから……！！`,ENG:`I am sorry... So please...!!`,TWN:`對不起，對不起……我拜託你……！！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_HATE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`예하?`,JPN:`猊下？`,ENG:`Your Eminence?`,TWN:`主教？`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`BIBLIDES_VATICAN_NULL_SHORT`,text:{KOREA:`예하……!! 예하!!`,JPN:`猊下……！！　猊下！！`,ENG:`Your Eminence...! Eminence!!`,TWN:`主教……！！主教！！`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`BIBLIDES_VATICAN_NULL_SHORT`,face:`UNIT_HATE`},R:null}}}];export{e as default};